interface CustomCursorProps {
  variant?: "default" | "dot" | "crosshair" | "glow" | "trail" | "none";
  color?: string;
  trailCount?: number;
  size?: number;
}

export function CustomCursor({
  variant = "default",
  color = "#a855f7",
  trailCount = 6,
  size = 20
}: CustomCursorProps) {
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [trail, setTrail] = useState<Array<{ x: number; y: number; id: number }>>([]);
  const [isVisible, setIsVisible] = useState(false);
  const [isHovering, setIsHovering] = useState(false);
  const trailRef = useRef(0);

  useEffect(() => {
    const isMobile = window.innerWidth < 768;
    const prefersReduced = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (isMobile || prefersReduced) return;

    setIsVisible(true);

    const handleMouseMove = (e: MouseEvent) => {
      setPosition({ x: e.clientX, y: e.clientY });

      if (variant === "trail") {
        setTrail((prev) => {
          const newTrail = [{ x: e.clientX, y: e.clientY, id: trailRef.current++ }, ...prev];
          return newTrail.slice(0, trailCount + 1);
        });
      }
    };

    const handleMouseEnter = () => setIsVisible(true);
    const handleMouseLeave = () => setIsVisible(false);

    // Detect hover over interactive elements
    const handleMouseOver = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      const interactive = target.closest("a, button, input, textarea, select, [role='button'], label");
      setIsHovering(!!interactive);
    };

    window.addEventListener("mousemove", handleMouseMove);
    window.addEventListener("mouseover", handleMouseOver);
    document.addEventListener("mouseenter", handleMouseEnter);
    document.addEventListener("mouseleave", handleMouseLeave);

    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
      window.removeEventListener("mouseover", handleMouseOver);
      document.removeEventListener("mouseenter", handleMouseEnter);
      document.removeEventListener("mouseleave", handleMouseLeave);
    };
  }, [trailCount, variant]);

  if (variant === "none") return null;

  const trailElements = trail.map((point, index) => {
    const opacity = Math.max(0, 0.5 - index / trailCount);
    const scale = 1 - (index / trailCount) * 0.8;

    return (
      <motion.div
        key={point.id}
        initial={{ opacity: 0.5, scale: 1 }}
        animate={{ opacity: 0, scale }}
        transition={{ duration: 0.4, ease: "easeOut" }}
        className="fixed pointer-events-none z-[9999] rounded-full"
        style={{
          width: size * scale * 0.5,
          height: size * scale * 0.5,
          backgroundColor: color,
          boxShadow: `0 0 ${8 * opacity}px ${color}`,
          transform: `translate3d(${point.x - size * scale * 0.25}px, ${point.y - size * scale * 0.25}px, 0)`,
        }}
      />
    );
  });

  const renderDot = () => (
    <div
      className="fixed pointer-events-none z-[10000] transition-transform duration-150"
      style={{
        left: position.x - size / 2,
        top: position.y - size / 2,
        width: `${size}px`,
        height: `${size}px`,
        transform: `translate3d(0, 0, 0) scale(${isHovering ? 1.5 : 1})`,
        opacity: isVisible ? 1 : 0,
      }}
    >
      <div
        className="w-full h-full rounded-full border-2 transition-colors duration-200"
        style={{
          borderColor: color,
          boxShadow: `0 0 ${isHovering ? 15 : 8}px ${color}80`,
          backgroundColor: isHovering ? `${color}30` : "transparent",
        }}
      />
    </div>
  );

  const renderCrosshair = () => (
    <div
      className="fixed pointer-events-none z-[10000]"
      style={{
        left: position.x - size / 2,
        top: position.y - size / 2,
        width: `${size}px`,
        height: `${size}px`,
        transform: `translate3d(0, 0, 0)`,
        opacity: isVisible ? 1 : 0,
      }}
    >
      <div className="absolute inset-0 border-2 rounded-full" style={{ borderColor: color, boxShadow: `0 0 ${size * 2}px ${color}` }} />
      <div className="absolute top-1/2 left-1/2 w-0.5 h-6 bg-white/80 -translate-x-1/2 -translate-y-1/2" style={{ boxShadow: `0 0 ${size}px ${color}` }} />
      <div className="absolute top-1/2 left-1/2 h-0.5 w-6 bg-white/80 -translate-x-1/2 -translate-y-1/2" style={{ boxShadow: `0 0 ${size}px ${color}` }} />
    </div>
  );

  const renderGlow = () => (
    <div
      className="fixed pointer-events-none z-[10000]"
      style={{
        left: position.x - size,
        top: position.y - size,
        width: `${size * 2}px`,
        height: `${size * 2}px`,
        transform: `translate3d(0, 0, 0)`,
        opacity: isVisible ? 1 : 0,
      }}
    >
      <div
        className="absolute inset-0 rounded-full"
        style={{
          backgroundColor: color,
          opacity: 0.15,
          filter: `blur(${size}px)`,
        }}
      />
    </div>
  );

  return (
    <div className="fixed inset-0 pointer-events-none z-[9998]" style={{ display: isVisible ? "block" : "none" }}>
      {variant === "dot" && renderDot()}
      {variant === "crosshair" && renderCrosshair()}
      {variant === "glow" && renderGlow()}
      {variant === "trail" && trailElements}
      {variant === "default" && renderDot()}
    </div>
  );
}

"use client";

import { useEffect, useRef } from "react";

export function CRTOverlay({
  intensity = 0.05,
  scanlineOpacity = 0.03
}: {
  intensity?: number;
  scanlineOpacity?: number;
}) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number | undefined>(undefined);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    // Respect reduced motion
    const prefersReduced = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReduced) return;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    resize();
    window.addEventListener("resize", resize);

    const animate = () => {
      const width = canvas.width;
      const height = canvas.height;

      ctx.clearRect(0, 0, width, height);

      // Scanlines
      ctx.globalAlpha = scanlineOpacity;
      ctx.fillStyle = "#000";
      for (let y = 0; y < height; y += 4) {
        ctx.fillRect(0, y, width, 2);
      }

      // Very subtle noise
      ctx.globalAlpha = intensity * 0.2;
      for (let i = 0; i < 100; i++) {
        const x = Math.random() * width;
        const y = Math.random() * height;
        ctx.fillStyle = Math.random() > 0.5 ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.1)";
        ctx.fillRect(x, y, 1, 1);
      }

      animationRef.current = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      window.removeEventListener("resize", resize);
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [intensity, scanlineOpacity]);

  return (
    <canvas
      ref={canvasRef}
      className="fixed inset-0 pointer-events-none z-[9998] opacity-40"
      style={{ mixBlendMode: "overlay" }}
    />
  );
}

export function ScanlinesOnly({ opacity = 0.05 }: { opacity?: number }) {
  return (
    <div
      className="fixed inset-0 pointer-events-none z-[9997]"
      style={{
        backgroundImage:
          "repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.15) 2px, rgba(0,0,0,0.15) 4px)",
        opacity,
        mixBlendMode: "multiply",
      }}
    />
  );
}

"use client";

import { useEffect, useRef } from 'react';

interface ParticleProps {
  type?: 'stars' | 'glitch' | 'snow' | 'hearts' | 'matrix' | 'rainbow' | 'pulse';
  count?: number;
  size?: number;
  speed?: number;
  opacity?: number;
  color?: string | string[];
  className?: string;
}

export function ParticleEffect({
  type = 'stars',
  count = 30,
  size = 2,
  speed = 1,
  opacity = 0.5,
  color,
  className = ''
}: ParticleProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number | undefined>(undefined);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (prefersReduced) return;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    resize();
    window.addEventListener('resize', resize);

    const colorMap: Record<string, string[]> = {
      stars: ['#fff', '#a855f7', '#ec4899', '#3b82f6', '#10b981'],
      glitch: ['#ff0', '#f00', '#0ff', '#0f0', '#00f', '#f0f'],
      snow: ['#fff', '#f8f8ff', '#f0f8ff', '#e6e6fa'],
      hearts: ['#ff0000', '#ff69b4', '#ff1493', '#db7093'],
      matrix: ['#0f0', '#0ff', '#00f', '#f0f', '#ff0', '#ffff00'],
      rainbow: ['#ff0000', '#ff7f00', '#ffff00', '#00ff00', '#0000ff', '#4b0082', '#9400d3'],
      pulse: ['#a855f7', '#ec4899', '#3b82f6', '#10b981']
    };

    const colors = color
      ? Array.isArray(color)
        ? color
        : [color]
      : colorMap[type] || colorMap.stars;

    interface Particle {
      x: number;
      y: number;
      vx: number;
      vy: number;
      radius: number;
      color: string;
      alpha: number;
      phase: number;
    }

    const particles: Particle[] = [];

    for (let i = 0; i < count; i++) {
      particles.push({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        vx: (Math.random() - 0.5) * speed * 2,
        vy: (Math.random() - 0.5) * speed * 2,
        radius: Math.random() * size + 0.5,
        color: colors[Math.floor(Math.random() * colors.length)],
        alpha: Math.random() * opacity + 0.2,
        phase: Math.random() * Math.PI * 2,
      });
    }

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      particles.forEach((p) => {
        p.x += p.vx;
        p.y += p.vy;

        if (p.x < 0) p.x = canvas.width;
        if (p.x > canvas.width) p.x = 0;
        if (p.y < 0) p.y = canvas.height;
        if (p.y > canvas.height) p.y = 0;

        p.phase += 0.03;

        ctx.globalAlpha = p.alpha * (type === 'pulse' ? Math.sin(p.phase) * 0.5 + 0.5 : 1);
        ctx.fillStyle = p.color;

        switch (type) {
          case 'stars':
          case 'snow':
          case 'pulse':
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.radius * (type === 'pulse' ? Math.sin(p.phase) * 0.5 + 1 : 1), 0, Math.PI * 2);
            ctx.fill();
            // Add glow for stars
            if (type === 'stars') {
              ctx.globalAlpha = p.alpha * 0.3;
              ctx.beginPath();
              ctx.arc(p.x, p.y, p.radius * 2, 0, Math.PI * 2);
              ctx.fill();
            }
            break;

          case 'glitch':
            ctx.fillRect(p.x, p.y, p.radius * 2, p.radius * 2);
            break;

          case 'hearts':
            ctx.font = `${p.radius * 2}px Arial`;
            ctx.fillText('❤', p.x, p.y);
            break;

          case 'matrix':
            ctx.font = `${p.radius * 2}px monospace`;
            ctx.fillText(Math.random() > 0.5 ? '1' : '0', p.x, p.y);
            break;

          case 'rainbow':
            ctx.font = `${p.radius * 1.5}px monospace`;
            ctx.fillText('★', p.x, p.y);
            break;
        }
      });

      animationRef.current = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      window.removeEventListener('resize', resize);
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [type, count, size, speed, opacity, color]);

  return (
    <canvas
      ref={canvasRef}
      className={`fixed inset-0 pointer-events-none z-[9995] ${className}`}
      style={{ pointerEvents: 'none', zIndex: 9995 }}
    />
  );
}

